INPUT VALIDATOR:
// CIL v5.2 INPUT VALIDATOR — COLLECTIVE CONSENSUS BUILD
// Changes: Run-ID generation, data sanity checks, enhanced validation
// [FIX v5.2] All output fields use no-underscore convention

const input = $input.first().json;
const runId = `RUN-${new Date().toISOString().replace(/[-:T]/g, '').slice(0,14)}-${Math.random().toString(36).slice(2,6)}`;

// Schema validation
const requiredFields = ['ticker'];
const missing = requiredFields.filter(f => !input[f]);
if (missing.length > 0) {
  throw new Error(`VALIDATOR FAIL: Missing required fields: ${missing.join(', ')}`);
}

// [EDIT — RAZIEL] Data sanity checks
const ticker = (input.ticker || '').toUpperCase().trim();
if (!/^[A-Z]{1,5}$/.test(ticker)) {
  throw new Error(`VALIDATOR FAIL: Invalid ticker format: ${ticker}`);
}

// [EDIT — RAZIEL] Validate HUNTER payload if present
const hunterData = input.hunterdata || input.hunter_data || null;
if (hunterData) {
  // Price sanity
  if (hunterData.price !== undefined && hunterData.price <= 0) {
    throw new Error(`VALIDATOR FAIL: Price <= 0 for ${ticker}: ${hunterData.price}`);
  }
  // Volume sanity
  if (hunterData.volume !== undefined && hunterData.volume <= 0) {
    throw new Error(`VALIDATOR FAIL: Volume <= 0 for ${ticker}: ${hunterData.volume}`);
  }
  // Data freshness — reject if HUNTER timestamp > 24hrs old
  if (hunterData.timestamp) {
    const age = Date.now() - new Date(hunterData.timestamp).getTime();
    if (age > 86400000) {
      throw new Error(`VALIDATOR FAIL: HUNTER data stale (${Math.round(age/3600000)}hrs old)`);
    }
  }
}

// [EDIT — URIEL] Run-ID traceability
const validated = {
  runid: runId,
  ticker: ticker,
  thesis: input.thesis || `Analyze ${ticker} for trade opportunity`,
  context: input.context || '',
  hunterdata: hunterData,
  triggersource: input.triggersource || input.trigger_source || 'manual',
  timestamp: new Date().toISOString(),
  mode: input.mode || 'DEEP_DIVE'
};

return { json: validated };

AGENT PAYLOAD BUILDER:
// CIL v5.2 AGENT PAYLOAD BUILDER — Updated Model Roster March 4, 2026
// URIEL:   gpt-5.2          (OpenAI flagship — strategic macro)
// COLOSSUS: grok-4          (xAI flagship — contrarian sentiment)  
// HANIEL:  gemini-3.1-pro-preview (Google — gemini-3-pro-preview DEAD March 9)
// RAZIEL:  deepseek-chat    (DeepSeek V3.2 API alias — adversarial stress test)
// SARIEL:  sonar-pro        (Perplexity Sonar Pro — live intelligence)
// [FIX v5.2] hunterdata field name, no-underscore convention

const input = $input.first().json;
const pass1Routing = input.pass1routing || input.pass1_routing || {};

const agents = {
  URIEL: {
    model: 'gpt-5.2',
    format: 'openai',
    role: 'Strategic Macro Analyst',
    bias: 'Bull case builder — find the strongest path to yes'
  },
  COLOSSUS: {
    model: 'grok-4',
    format: 'xai',
    role: 'Contrarian Sentiment Analyst',
    bias: 'Contrarian by default — challenge every assumption'
  },
  HANIEL: {
    model: 'gemini-3.1-pro-preview',
    format: 'google',
    role: 'Fundamental Research Analyst',
    bias: 'Evidence-only — no speculation, cite data sources'
  },
  RAZIEL: {
    model: 'deepseek-chat',
    format: 'deepseek',
    role: 'Adversarial Stress Tester',
    bias: 'Bear case builder — find every way this trade fails'
  },
  SARIEL: {
    model: 'sonar-pro',
    format: 'perplexity',
    role: 'Live Intelligence Analyst',
    bias: 'Recency-weighted — prioritize latest data, flag stale inputs'
  }
};

const payloads = [];

for (const [name, config] of Object.entries(agents)) {
  const directiveField = `${name.toLowerCase()}_directive`;
  const directive = pass1Routing[directiveField] 
    || `Analyze ${input.ticker} from your perspective as ${config.role}`;

  const systemPrompt = `You are ${name}, ${config.role} for the Uriel Covenant AI Collective.
ANALYTICAL BIAS: ${config.bias}
TICKER: ${input.ticker}
RUN-ID: ${input.runid}

Your analysis MUST include ALL of these fields:
1. direction: BULLISH / BEARISH / NEUTRAL
2. confidence: 0-100 (be honest, not inflated)
3. catalysts: array of specific, date-bound catalysts if possible
4. risks: array of top 3 risks to the thesis
5. counter_thesis: the strongest argument AGAINST your position
6. timeline: expected move timeframe (e.g. "2-4 weeks")
7. data_gaps: what data you wish you had but don't

Respond in valid JSON only. No markdown fences, no commentary, no backticks.
Start your response with { and end with }`;

  const userPrompt = `THESIS: ${input.thesis}
CONTEXT: ${input.context || 'None provided'}
HUNTER DATA: ${JSON.stringify(input.hunterdata || {})}
SPECIFIC DIRECTIVE: ${directive}

Analyze and respond in pure JSON.`;

  payloads.push({
    json: {
      agent: name,
      runid: input.runid,
      ticker: input.ticker,
      systemprompt: systemPrompt,
      userprompt: userPrompt,
      model: config.model,
      format: config.format
    }
  });
}

return payloads;

