// URIEL RESPONSE PARSER + SENTINEL
// Extracts response from OpenAI format with full diagnostic tagging

const raw = $input.first().json;

// === SENTINEL DIAGNOSTIC BUILDER ===
function buildSentinel(status, errorType, errorDetail, fix) {
  return {
    node: 'URIEL — OpenAI',
    parser: 'URIEL PARSER',
    agent: 'URIEL',
    api: 'OpenAI',
    credential: 'OpenAI API Key',
    status: status,
    error_type: errorType,
    error_detail: errorDetail,
    fix: fix,
    timestamp: new Date().toISOString()
  };
}

// === DETECT HTTP-LEVEL FAILURES ===
// When continueOnFail=true, n8n may pass error objects or raw HTTP responses
const httpStatus = raw.statusCode || raw.status || raw.code || null;
const errorMsg = raw.error?.message || raw.message || raw.error_message || null;

// Check for completely empty response (node failed silently)
if (!raw || (typeof raw === 'object' && Object.keys(raw).length === 0)) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: null,
    _sentinel: buildSentinel('DEAD', 'EMPTY_RESPONSE',
      'Node returned empty object. API call likely never executed.',
      'CHECK: n8n node "URIEL — OpenAI" → Credential dropdown must show "OpenAI API Key". If missing, create Header Auth credential in n8n Settings → Credentials.')
  }}];
}

// Auth failures (401, 403)
if (httpStatus === 401 || (errorMsg && errorMsg.toLowerCase().includes('unauthorized'))) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: JSON.stringify(raw).substring(0, 300),
    _sentinel: buildSentinel('AUTH_FAIL', 'HTTP_401',
      'API returned 401 Unauthorized. Key is invalid or expired.',
      'FIX: n8n Settings → Credentials → "OpenAI API Key" → Verify Header Value is correct. For OpenAI: Header Name="Authorization", Value="Bearer <key>".')
  }}];
}

if (httpStatus === 403 || (errorMsg && errorMsg.toLowerCase().includes('forbidden'))) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: JSON.stringify(raw).substring(0, 300),
    _sentinel: buildSentinel('AUTH_FAIL', 'HTTP_403',
      'API returned 403 Forbidden. Key lacks required permissions or IP is blocked.',
      'FIX: Check OpenAI dashboard for key permissions. Verify key is not IP-restricted. Credential: "OpenAI API Key".')
  }}];
}

// Rate limiting (429)
if (httpStatus === 429 || (errorMsg && errorMsg.toLowerCase().includes('rate'))) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: JSON.stringify(raw).substring(0, 300),
    _sentinel: buildSentinel('RATE_LIMIT', 'HTTP_429',
      'API rate limit hit. Too many requests.',
      'WAIT: OpenAI rate limit exceeded. Wait 60s and retry. If persistent, check OpenAI dashboard for tier limits.')
  }}];
}

// Timeout
if ((errorMsg && (errorMsg.toLowerCase().includes('timeout') || errorMsg.toLowerCase().includes('ETIMEDOUT'))) || httpStatus === 408 || httpStatus === 504) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: JSON.stringify(raw).substring(0, 300),
    _sentinel: buildSentinel('TIMEOUT', 'TIMEOUT',
      'API call timed out.',
      'FIX: n8n node "URIEL — OpenAI" → Settings tab → Timeout. Current: 30000ms. Try 60000ms. If OpenAI is consistently slow, check their status page.')
  }}];
}

// Server errors (500, 502, 503)
if (httpStatus >= 500 && httpStatus < 600) {
  return [{ json: {
    agent: 'URIEL', status: 'error', data: null, raw: JSON.stringify(raw).substring(0, 300),
    _sentinel: buildSentinel('SERVER_ERROR', 'HTTP_' + httpStatus,
      'OpenAI returned server error ' + httpStatus + '.',
      'WAIT: OpenAI is having issues (HTTP ' + httpStatus + '). Check status.openai.com or retry in a few minutes. Not your config.')
  }}];
}

// Explicit error object in response
if (raw.error) {
  return [{ json: {
    agent: 'URIEL', status: 'error',
    error: raw.error.message || JSON.stringify(raw.error),
    data: null, raw: null,
    _sentinel: buildSentinel('API_ERROR', 'ERROR_RESPONSE',
      raw.error.message || JSON.stringify(raw.error).substring(0, 200),
      'CHECK: OpenAI error response. Node: "URIEL — OpenAI". Review the request body — model name, parameters, or prompt format may be wrong.')
  }}];
}

// === TRY NORMAL PARSE ===
try {
  const content = raw.choices[0].message.content;
  if (!content || content.trim().length === 0) {
    return [{ json: {
      agent: 'URIEL', status: 'error', data: null, raw: '',
      _sentinel: buildSentinel('EMPTY_CONTENT', 'EMPTY_BODY',
        'API returned 200 but content field is empty.',
        'CHECK: Node "URIEL — OpenAI" → Request Body. Model may have refused or returned empty. Check OpenAI usage dashboard.')
    }}];
  }

  // === BULLETPROOF FENCE STRIP (v5.2 patch) ===
// === BULLETPROOF FENCE STRIP (v5.2 patch) ===
  let cleaned = content
    .replace(/^```json\s*/i, '')
    .replace(/^```\w*\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  const parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : null;

  return [{ json: {
    agent: 'URIEL',
    status: parsed ? 'success' : 'raw_only',
    data: parsed,
    raw: content,
    _sentinel: buildSentinel(parsed ? 'OK' : 'PARSE_WARN',
      parsed ? null : 'NO_JSON',
      parsed ? null : 'Response contained text but no parseable JSON object.',
      parsed ? null : 'INFO: URIEL responded in plain text. COLLECTIVE ASSEMBLER will use raw text. Not a failure, but structured JSON is preferred for scoring.')
  }}];
} catch (e) {
  return [{ json: {
    agent: 'URIEL', status: 'parse_error',
    error: e.message,
    data: null,
    raw: JSON.stringify(raw).substring(0, 500),
    _sentinel: buildSentinel('PARSE_FAIL', 'EXCEPTION',
      e.message,
      'CHECK: OpenAI response format changed. Node "URIEL — OpenAI" → expected path: choices[0].message.content. Actual response structure may differ. Raw data logged.')
  }}];
}

