// COLLECTIVE ASSEMBLER v1.2
// Takes all 5 agent outputs from the merge and builds the synthesis payload
// [FIX] Correctly extracts runid and ticker from INPUT VALIDATOR node
// [FIX v5.2] All output fields use no-underscore convention

const items = $input.all();
const originalInput = $('INPUT VALIDATOR').first().json;
const agents = {};
const errors = [];
const agentNames = ['URIEL', 'COLOSSUS', 'HANIEL', 'RAZIEL', 'SARIEL'];

// Collect all agent outputs from merged parser results
for (const item of items) {
  const d = item.json;
  if (d.agent) {
    agents[d.agent] = {
      status: d.status,
      data: d.data || null,
      error: d.error || null,
      raw: d.raw || null
    };
    if (d.status !== 'success') {
      errors.push(`${d.agent}: ${d.status} - ${d.error || 'unknown'}`);
    }
  }
}

// Check which agents reported
const reporting = {};
for (const name of agentNames) {
  reporting[name] = agents[name] ? agents[name].status : 'missing';
}

const successCount = Object.values(reporting).filter(s => s === 'success').length;

const synthesisPayload = {
  runid: originalInput.runid || 'NO-RUN-ID',
  ticker: originalInput.ticker || 'UNKNOWN',
  thesis: originalInput.thesis || '',
  context: originalInput.context || '',
  hunterdata: originalInput.hunterdata || {},
  triggersource: originalInput.triggersource || 'unknown',
  timestamp: originalInput.timestamp || new Date().toISOString(),
  agentsreporting: reporting,
  agentssuccesscount: successCount,
  agentstotal: 5,
  agent_outputs: agents,
  errors: errors,
  assemblytimestamp: new Date().toISOString()
};
return [{ json: synthesisPayload }];

CASCADE VALIDATOR:
// CIL v5.2 CASCADE VALIDATOR — COLLECTIVE CONSENSUS BUILD
// [EDIT — URIEL + RAZIEL] Deterministic gates primary. LLM confidence annotative.
// [FIX] Extract agent data from COLLECTIVE ASSEMBLER's agent_outputs structure
// [FIX] Extract runid and ticker from COLLECTIVE ASSEMBLER structure
// [FIX v5.2] All output fields use no-underscore convention to match data tables

const input = $input.first().json;

// [FIX] Pass2 synthesis is optional - CASCADE works without it
const pass2 = {};

// [FIX] Handle COLLECTIVE ASSEMBLER output structure
// COLLECTIVE ASSEMBLER outputs agent_outputs (object with agent names as keys)
// Each agent has: { status, data, error, raw }
const agents = input.agent_outputs 
  ? Object.values(input.agent_outputs).map(a => a.data).filter(d => d) 
  : (input.agentresults || []);

const hunterData = input.hunterdata || input.hunter_data || {};

// [FIX] Extract runid and ticker from COLLECTIVE ASSEMBLER top-level fields
// COLLECTIVE ASSEMBLER passes through runid and ticker from INPUT VALIDATOR
let runId = input.runid || 'NO-RUN-ID';
let ticker = input.ticker || 'UNKNOWN';

// Count valid agent responses
const validAgents = agents.filter(a => a && a.direction && !a.error);
const totalAgents = 5;
const directions = validAgents.map(a => (a.direction || '').toUpperCase());
const confidences = validAgents.map(a => parseFloat(a.confidence) || 0);

// Directional consensus
const bullCount = directions.filter(d => d === 'BULLISH').length;
const bearCount = directions.filter(d => d === 'BEARISH').length;
const consensusDirection = bullCount >= 3 ? 'BULLISH' : bearCount >= 3 ? 'BEARISH' : 'NO_CONSENSUS';
const hasConsensus = bullCount >= 3 || bearCount >= 3;

// Average confidence
const avgConfidence = confidences.length > 0 ? confidences.reduce((a,b) => a+b, 0) / confidences.length : 0;

// Catalyst check
const catalysts = validAgents.filter(a => a.catalysts && a.catalysts.length > 0);
const hasCatalyst = catalysts.length >= 1;

// Timeline alignment
const timelines = validAgents.map(a => a.timeline || '').filter(t => t);
const hasTimelineAlign = timelines.length >= 3;

// Counter-thesis check
const counterTheses = validAgents.filter(a => a.counter_thesis && a.counter_thesis.length > 10);
const hasCounterThesis = counterTheses.length >= 1;

// Risk check — any agent flag kill-level risk?
const killRisks = validAgents.filter(a => {
  const risks = (a.risks || []).map(r => (typeof r === 'string' ? r : r.description || '').toLowerCase());
  return risks.some(r => r.includes('kill') || r.includes('fraud') || r.includes('delisted') || r.includes('bankruptcy'));
});
const noKillRisk = killRisks.length === 0;

// ============================================================
// [EDIT — URIEL + RAZIEL] DETERMINISTIC GATES
// ============================================================

// Gate 3b: Data Completeness (DETERMINISTIC — replaces Gate 3)
const hunterModules = Object.keys(hunterData).filter(k => hunterData[k] !== null && hunterData[k] !== undefined);
const totalHunterModules = 21;
const dataCompleteness = hunterModules.length / totalHunterModules;
const gate3b_pass = dataCompleteness >= 0.80;

// Gate 4: Risk/Reward (DETERMINISTIC)
const rr = pass2.risk_reward_ratio || 0;
const gate4_pass = rr >= 2.0;

// Gate 7 DETERMINISTIC KILL-CHECKS [EDIT — URIEL + HANIEL]
const earningsWithin5Days = hunterData.earnings_days_away !== undefined && hunterData.earnings_days_away <= 5;
const lowLiquidity = hunterData.avg_volume !== undefined && hunterData.avg_volume < 100000;
const dilutionHigh = hunterData.dilution_risk === 'HIGH';
const s3Active = hunterData.shelf_registration_active === true;

let deterministicKill = false;
let killReason = '';
if (earningsWithin5Days && !(input.thesis || '').toLowerCase().includes('earnings')) {
  deterministicKill = true;
  killReason = 'Earnings within 5 trading days (non-earnings thesis)';
}
if (lowLiquidity) {
  deterministicKill = true;
  killReason = 'Avg daily volume < 100K (liquidity kill)';
}

// Gate 8: IRONCLAD position sizing (DETERMINISTIC)
const gate8_pass = true;

// ============================================================
// GATE SCORECARD
// ============================================================
const gates = {
  gate1: { name: 'Data Sufficiency', pass: validAgents.length >= 3, type: 'DETERMINISTIC', detail: `${validAgents.length}/${totalAgents} agents returned valid data` },
  gate2: { name: 'Directional Consensus', pass: hasConsensus, type: 'AGENT-DERIVED', detail: `${consensusDirection} (Bull:${bullCount} Bear:${bearCount})` },
  gate3: { name: 'Confidence Floor (ANNOTATIVE)', pass: avgConfidence >= 60, type: 'ANNOTATIVE', detail: `Avg: ${avgConfidence.toFixed(1)}% — LOGGED ONLY, non-decisive` },
  gate3b: { name: 'Data Completeness', pass: gate3b_pass, type: 'DETERMINISTIC', detail: `${(dataCompleteness*100).toFixed(0)}% HUNTER modules returned data (≥80% required)` },
  gate4: { name: 'Risk/Reward Ratio', pass: gate4_pass, type: 'DETERMINISTIC', detail: `R:R = ${rr.toFixed(1)}:1 (≥2:1 required)` },
  gate5: { name: 'Catalyst Identified', pass: hasCatalyst, type: 'AGENT-DERIVED', detail: `${catalysts.length} agents identified catalysts` },
  gate6: { name: 'Timeline Alignment', pass: hasTimelineAlign, type: 'AGENT-DERIVED', detail: `${timelines.length} agents provided timelines` },
  gate7: { name: 'No Disqualifying Risk', pass: noKillRisk && !deterministicKill, type: 'HYBRID', detail: deterministicKill ? `DETERMINISTIC KILL: ${killReason}` : `${killRisks.length} kill-level risks flagged` },
  gate7_5: { name: 'Counter-Thesis Survived', pass: hasCounterThesis, type: 'AGENT-DERIVED', detail: `${counterTheses.length} agents provided counter-thesis` },
  gate8: { name: 'Position Sizing (IRONCLAD)', pass: gate8_pass, type: 'DETERMINISTIC', detail: 'IRONCLAD rules checked' }
};

// Count DECISIVE gates only (exclude annotative Gate 3)
const decisiveGates = Object.entries(gates).filter(([k,v]) => v.type !== 'ANNOTATIVE');
const passCount = decisiveGates.filter(([k,v]) => v.pass).length;
const totalDecisive = decisiveGates.length;

// Flags [EDIT — HANIEL]
const flags = [];
if (dilutionHigh) flags.push('⚠️ DILUTION RISK HIGH (shares Δ > 2% QoQ)');
if (s3Active) flags.push('⚠️ ACTIVE S-3 SHELF REGISTRATION');

// Cascade score
let cascadeLevel;
if (passCount >= totalDecisive) cascadeLevel = 'FULL_CONFIDENCE';
else if (passCount >= totalDecisive - 2) cascadeLevel = 'HIGH_CONFIDENCE';
else if (passCount >= totalDecisive - 4) cascadeLevel = 'MODERATE';
else cascadeLevel = 'LOW';

return {
  json: {
    runid: runId,
    ticker: ticker,
    cascadelevel: cascadeLevel,
    gatespassed: passCount,
    gatestotal: totalDecisive,
    gates: gates,
    flags: flags,
    consensusdirection: consensusDirection,
    avgconfidenceannotative: avgConfidence.toFixed(1),
    datacompleteness: (dataCompleteness * 100).toFixed(0) + '%',
    agentresults: validAgents,
    pass2synthesis: pass2,
    hunterdata: hunterData,
    timestamp: new Date().toISOString()
  }
};

